/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataFieldEventHandler(formDataFieldStr(VendEditInvoice, VendInvoiceInfoLine, ETGActualPurchPrice), FormDataFieldEventType::Modified)]
public static void ETGActualPurchPrice_OnModified(FormDataObject sender, FormDataFieldEventArgs e)
{
    if(ETGACFParameters::find().EnablePTBFContractsPurch == NoYes::Yes)
    {
        FormDataSource  VendInvoiceInfoLine_ds = sender.datasource();
        VendInvoiceInfoLine VendInvoiceInfoLine = VendInvoiceInfoLine_ds.cursor();
        PurchLine   PurchLine = PurchLine::findInventTransId(VendInvoiceInfoLine.InventTransId);

        if(VendInvoiceInfoLine.ETGActualPurchPrice != 0)
        {
            if(VendInvoiceInfoLine.ETGActualQuantity != 0 )
            {
                if(PurchLine.LinePercent == 0)
                {
                    VendInvoiceInfoLine.ETGActualLineAmt = ((VendInvoiceInfoLine.ETGActualPurchPrice - VendInvoiceInfoLine.PurchPrice)* VendInvoiceInfoLine.ETGActualQuantity);
                }
                else
                {
                    VendInvoiceInfoLine.ETGActualLineAmt = ( (VendInvoiceInfoLine.ETGActualPurchPrice * VendInvoiceInfoLine.ETGActualQuantity) -
                                                    (round(((VendInvoiceInfoLine.ETGActualPurchPrice * VendInvoiceInfoLine.ETGActualQuantity) * PurchLine.LinePercent) /100 ,0.01)) ) -
                                                   ((VendInvoiceInfoLine.PurchPrice * VendInvoiceInfoLine.ETGActualQuantity) -
                                                    (round(((VendInvoiceInfoLine.PurchPrice * VendInvoiceInfoLine.ETGActualQuantity) * PurchLine.LinePercent) /100 ,0.01)));
                }
            }
            else
            {
                if(PurchLine.LinePercent == 0)
                {
                    VendInvoiceInfoLine.ETGActualLineAmt = ((VendInvoiceInfoLine.ETGActualPurchPrice - VendInvoiceInfoLine.PurchPrice)* PurchLine.PurchQty);
                }
                else
                {
                    VendInvoiceInfoLine.ETGActualLineAmt = ( (VendInvoiceInfoLine.ETGActualPurchPrice * PurchLine.PurchQty) -
                                                    (round(((VendInvoiceInfoLine.ETGActualPurchPrice * PurchLine.PurchQty) * PurchLine.LinePercent) /100 ,0.01)) ) -
                                                   ((VendInvoiceInfoLine.PurchPrice * PurchLine.PurchQty) -
                                                    (round(((VendInvoiceInfoLine.PurchPrice * PurchLine.PurchQty) * PurchLine.LinePercent) /100 ,0.01)));
                }
            }
        }
        else
        {
            VendInvoiceInfoLine.ETGActualLineAmt = 0;
        }
    }
}

